namespace Endereco.Application.Enderecos.Commands;

public class DeleteEnderecoCommandHandler : IRequestHandler<DeleteEnderecoCommand, bool>
{
    private readonly IEnderecoRepository _repository;

    public DeleteEnderecoCommandHandler(IEnderecoRepository repository)
    {
        _repository = repository;
    }

    public async Task<bool> Handle(DeleteEnderecoCommand request, CancellationToken cancellationToken)
    {
        var endereco = await _repository.GetByIdAsync(request.Id);
        if (endereco is null) return false;

        await _repository.DeleteAsync(endereco);
        return true;
    }
}

using MediatR;

namespace Endereco.Application.Enderecos.Queries;

public record GetAllEnderecosQuery : IRequest<IEnumerable<EnderecoDto>>;

public record EnderecoDto(Guid Id, string Rua, string Numero, string Cidade, string Estado, string CEP);

using Endereco.Domain.Interfaces;
using MediatR;

namespace Endereco.Application.Enderecos.Queries;

public class GetAllEnderecosQueryHandler : IRequestHandler<GetAllEnderecosQuery, IEnumerable<EnderecoDto>>
{
    private readonly IEnderecoRepository _repository;

    public GetAllEnderecosQueryHandler(IEnderecoRepository repository)
    {
        _repository = repository;
    }

    public async Task<IEnumerable<EnderecoDto>> Handle(GetAllEnderecosQuery request, CancellationToken cancellationToken)
    {
        var enderecos = await _repository.GetAllAsync();
        return enderecos.Select(e => new EnderecoDto(e.Id, e.Rua, e.Numero, e.Cidade, e.Estado, e.CEP));
    }
}

using MediatR;

namespace Endereco.Application.Enderecos.Queries;

public record GetEnderecoByIdQuery(Guid Id) : IRequest<EnderecoDto>;

using Endereco.Domain.Interfaces;
using MediatR;

namespace Endereco.Application.Enderecos.Queries;

public class GetEnderecoByIdQueryHandler : IRequestHandler<GetEnderecoByIdQuery, EnderecoDto>
{
    private readonly IEnderecoRepository _repository;

    public GetEnderecoByIdQueryHandler(IEnderecoRepository repository)
    {
        _repository = repository;
    }

    public async Task<EnderecoDto> Handle(GetEnderecoByIdQuery request, CancellationToken cancellationToken)
    {
        var endereco = await _repository.GetByIdAsync(request.Id);
        return endereco is null ? null : new EnderecoDto(endereco.Id, endereco.Rua, endereco.Numero, endereco.Cidade, endereco.Estado, endereco.CEP);
    }
}

namespace Endereco.Domain.Entities;

public class Endereco
{
    public Guid Id { get; private set; }
    public string Rua { get; private set; }
    public string Numero { get; private set; }
    public string Cidade { get; private set; }
    public string Estado { get; private set; }
    public string CEP { get; private set; }

    public Endereco(string rua, string numero, string cidade, string estado, string cep)
    {
        Id = Guid.NewGuid();
        Rua = rua;
        Numero = numero;
        Cidade = cidade;
        Estado = estado;
        CEP = cep;
    }

    public void Update(string rua, string numero, string cidade, string estado, string cep)
    {
        Rua = rua;
        Numero = numero;
        Cidade = cidade;
        Estado = estado;
        CEP = cep;
    }
}

using Endereco.Domain.Entities;

namespace Endereco.Domain.Interfaces;

public interface IEnderecoRepository
{
    Task<bool> ExistsAsync(string rua, string numero, string cidade, string estado, string cep);
    Task AddAsync(Endereco endereco);
    Task<Endereco> GetByIdAsync(Guid id);
    Task<IEnumerable<Endereco>> GetAllAsync();
    Task UpdateAsync(Endereco endereco);
    Task DeleteAsync(Endereco endereco);
}

using Endereco.Domain.Interfaces;
using Endereco.Infrastructure.Persistence;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;

namespace Endereco.Infrastructure;

public static class DependencyInjection
{
    public static IServiceCollection AddInfrastructureServices(this IServiceCollection services, IConfiguration configuration)
    {
        services.AddDbContext<EnderecoDbContext>(options =>
            options.UseInMemoryDatabase("EnderecoDb"));

        services.AddScoped<IEnderecoRepository, EnderecoRepository>();

        return services;
    }
}

using Endereco.Domain.Entities;
using Microsoft.EntityFrameworkCore;

namespace Endereco.Infrastructure.Persistence;

public class EnderecoDbContext : DbContext
{
    public EnderecoDbContext(DbContextOptions<EnderecoDbContext> options) : base(options) { }

    public DbSet<Endereco> Enderecos { get; set; }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Endereco>()
            .HasIndex(e => new { e.Rua, e.Numero, e.Cidade, e.Estado, e.CEP })
            .IsUnique();
    }
}

using Endereco.Domain.Entities;
using Endereco.Domain.Interfaces;
using Microsoft.EntityFrameworkCore;

namespace Endereco.Infrastructure.Persistence;

public class EnderecoRepository : IEnderecoRepository
{
    private readonly EnderecoDbContext _context;

    public EnderecoRepository(EnderecoDbContext context)
    {
        _context = context;
    }

    public async Task<bool> ExistsAsync(string rua, string numero, string cidade, string estado, string cep)
    {
        return await _context.Enderecos.AnyAsync(e =>
            e.Rua == rua &&
            e.Numero == numero &&
            e.Cidade == cidade &&
            e.Estado == estado &&
            e.CEP == cep);
    }

    public async Task AddAsync(Endereco endereco)
    {
        await _context.Enderecos.AddAsync(endereco);
        await _context.SaveChangesAsync();
    }

    public async Task<Endereco> GetByIdAsync(Guid id)
    {
        return await _context.Enderecos.FindAsync(id);
    }

    public async Task<IEnumerable<Endereco>> GetAllAsync()
    {
        return await _context.Enderecos.ToListAsync();
    }

    public async Task UpdateAsync(Endereco endereco)
    {
        _context.Enderecos.Update(endereco);
        await _context.SaveChangesAsync();
    }

    public async Task DeleteAsync(Endereco endereco)
    {
        _context.Enderecos.Remove(endereco);
        await _context.SaveChangesAsync();
    }
}
